
-- ============================================================
-- Gap 1: Update 5 key section exemplars to Principal-grade
-- ============================================================

UPDATE public.ai_review_section_config
SET example_good = E'A logistics operator managing 12 regional distribution centres loses approximately $2.3M annually to manual inventory reconciliation errors between their warehouse management system (SAP EWM) and ERP (SAP S/4HANA). Despite two previous improvement initiatives (2022 RPA pilot, 2023 middleware upgrade), the discrepancy rate remains at 47 incidents per week, each requiring 30–90 minutes of manual investigation by warehouse supervisors.\n\nRoot cause analysis (Ishikawa) identifies three failure modes: (1) batch-to-real-time timing mismatches causing 62% of discrepancies, (2) master data drift between systems accounting for 23%, and (3) exception-handling logic gaps covering the remaining 15%. Industry benchmarks (Gartner Supply Chain Top 25, 2024) indicate that top-quartile operators achieve <5 incidents/week at comparable scale.\n\nThe financial impact decomposes as: labour cost of investigation ($1.4M), downstream fulfilment delays ($0.6M), and inventory write-offs from unresolved discrepancies ($0.3M). Without intervention, planned expansion to 18 centres by Q3 2026 will scale the problem to an estimated $3.8M annually.',
    updated_at = now()
WHERE role_context = 'curation' AND section_key = 'problem_statement';

UPDATE public.ai_review_section_config
SET example_good = E'IN SCOPE:\n• Data synchronisation layer between SAP EWM and SAP S/4HANA, covering all 12 distribution centres and 3 data domains (inventory movements, master data, exception events)\n• Real-time event-driven architecture replacing current batch processing (target: <30 second propagation latency per MuleSoft Anypoint benchmarks)\n• Automated exception detection engine covering the three identified failure modes with configurable thresholds\n• Alerting and escalation workflow integrated with existing ServiceNow ITSM instance\n\nOUT OF SCOPE:\n• Changes to SAP EWM or S/4HANA core configuration, module upgrades, or licensing\n• Supplier-facing EDI interfaces and B2B gateway integrations\n• Mobile hardware (RF scanners, handheld devices) — firmware and OS are managed under a separate programme\n• Any warehouse process outside the inventory reconciliation workflow (e.g., putaway optimisation, slotting)\n• Data migration or historical data cleansing — solution operates on forward-flowing transactions only\n\nBOUNDARY ASSUMPTIONS:\n• Solution must operate within the existing network topology (hub-and-spoke VPN between DCs and central data centre)\n• Authentication via existing Azure AD tenant — no new identity provider\n• Performance SLA: sustain 500 transactions/minute during peak (Black Friday baseline from 2024)',
    updated_at = now()
WHERE role_context = 'curation' AND section_key = 'scope';

UPDATE public.ai_review_section_config
SET example_good = E'D1: Working middleware integration package with automated deployment script\n— Acceptance: IT Architect can deploy to staging environment without vendor support within 4 hours; all 12 DC connections established and health-checked green.\n— Standard: Must pass integration test suite (≥95% of 200+ test cases) against production-mirrored staging data.\n\nD2: Technical documentation package (minimum 25 pages)\n— Acceptance: Covers all configuration parameters, error codes, escalation procedures, and capacity planning guidelines.\n— Standard: Reviewed against IEEE 1063 documentation quality checklist; scores ≥80% on completeness assessment.\n— Cross-reference: Must align with scope boundary assumptions (network topology, Azure AD, performance SLA).\n\nD3: Exception detection ruleset with self-tuning capability\n— Acceptance: Passes automated regression test against 6-month historical transaction log with ≥95% detection coverage and <2% false positive rate.\n— Standard: Rules engine must be configurable by business users (warehouse supervisors) without code changes.\n— Benchmark: Detection latency <5 seconds per exception event (ref: Gartner real-time analytics benchmark).\n\nD4: Runbook and knowledge transfer package\n— Acceptance: Operations team completes 3 simulated incident scenarios without vendor assistance.\n— Standard: Mean time to resolution for simulated incidents <15 minutes.',
    updated_at = now()
WHERE role_context = 'curation' AND section_key = 'deliverables';

UPDATE public.ai_review_section_config
SET example_good = E'SCORING METHOD: Weighted multi-criteria, single panel (IT Architect + AP Manager + Warehouse Operations Lead)\n\n(1) Technical Performance — 40%\n— Method: Automated integration test suite against production-mirrored staging environment\n— Scorer: IT Architect\n— Benchmark: ≥95% test pass rate, <30s propagation latency, sustains 500 txn/min\n— Evidence: Test execution report with pass/fail counts, latency percentiles (p50, p95, p99)\n\n(2) Documentation Quality — 20%\n— Method: IEEE 1063 completeness checklist + deployment walkthrough\n— Scorer: IT Manager\n— Benchmark: ≥80% checklist score, successful unassisted staging deployment within 4 hours\n— Evidence: Checklist scorecard, deployment log with timestamps\n\n(3) Exception Detection Accuracy — 25%\n— Method: Historical log regression test (6-month dataset, ~14,000 transactions)\n— Scorer: AP Manager + Warehouse Operations Lead (joint)\n— Benchmark: ≥95% detection coverage, <2% false positive rate, <5s detection latency\n— Evidence: Confusion matrix, false positive analysis report\n\n(4) Operability & Knowledge Transfer — 15%\n— Method: 3 simulated incident scenarios executed by operations team without vendor support\n— Scorer: Warehouse Operations Lead\n— Benchmark: All scenarios resolved, MTTR <15 minutes average\n— Evidence: Scenario execution logs, MTTR measurements\n\nTotal: 100%. Minimum qualifying score: 60% overall with no single criterion below 40%.\nCross-reference: Criteria map directly to D1–D4 deliverables and scope performance SLA.',
    updated_at = now()
WHERE role_context = 'curation' AND section_key = 'evaluation_criteria';

UPDATE public.ai_review_section_config
SET example_good = E'PRIZE STRUCTURE:\n• First Prize: $75,000 USD — awarded to the highest-scoring submission meeting all acceptance criteria\n• Second Prize: $25,000 USD — awarded to the second-highest-scoring qualifying submission\n• Total Prize Pool: $100,000 USD\n\nPAYMENT TERMS:\n• Payment within 30 calendar days of IP transfer documentation execution\n• Wire transfer to solver-designated bank account (international transfers supported)\n• Prize conditional on passing all acceptance tests defined in D1–D4 deliverables section\n• No partial payments for incomplete submissions\n\nADDITIONAL INCENTIVES:\n• Both winning solvers receive a platform-verified case study publication (estimated value: enhanced solver profile visibility)\n• First-prize winner offered first-right-of-refusal for Phase 2 production deployment engagement (separate commercial terms)\n\nBUDGET CONTEXT:\n• Prize pool represents ~4.3% of the $2.3M annual cost of the problem — ROI-positive if the solution achieves even 50% of target improvement\n• Benchmark: Gartner innovation challenge benchmarks (2024) indicate median prize pools of $50K–$150K for middleware integration challenges at this complexity level\n\nNON-AWARD SCENARIO:\n• If no submission meets the minimum qualifying score (60% overall, no criterion below 40%), the prize pool is not awarded. Seeker may elect to extend the submission deadline by up to 30 days.',
    updated_at = now()
WHERE role_context = 'curation' AND section_key = 'reward_structure';

